package com.opengamma.strata.product.credit;

import java.io.Serializable;
import java.time.LocalDate;
import java.util.Map;
import java.util.NoSuchElementException;

import org.joda.beans.Bean;
import org.joda.beans.ImmutableBean;
import org.joda.beans.JodaBeanUtils;
import org.joda.beans.MetaBean;
import org.joda.beans.MetaProperty;
import org.joda.beans.gen.BeanDefinition;
import org.joda.beans.gen.ImmutableDefaults;
import org.joda.beans.gen.ImmutablePreBuild;
import org.joda.beans.gen.PropertyDefinition;
import org.joda.beans.impl.direct.DirectFieldsBeanBuilder;
import org.joda.beans.impl.direct.DirectMetaBean;
import org.joda.beans.impl.direct.DirectMetaProperty;
import org.joda.beans.impl.direct.DirectMetaPropertyMap;

import com.google.common.collect.ImmutableList;
import com.google.common.collect.ImmutableSet;
import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.Resolvable;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.date.DayCount;
import com.opengamma.strata.basics.date.DayCounts;
import com.opengamma.strata.basics.date.DaysAdjustment;
import com.opengamma.strata.basics.schedule.PeriodicSchedule;
import com.opengamma.strata.basics.schedule.Schedule;
import com.opengamma.strata.basics.schedule.SchedulePeriod;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.product.Product;
import com.opengamma.strata.product.common.BuySell;

/**
 * A CDS tranche product.
 * <p>
 * A CDS tranche is a slice of credit risk from a CDS index portfolio, defined by attachment and detachment points.
 * The tranche buyer receives protection on the underlying index between these points.
 * <p>
 * The protection buyer periodically pays fixed coupons to the protection seller until the expiry,
 * and in return, the protection buyer receives losses between the attachment and detachment points.
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * The underlying CDS index that this tranche is based on.
   * <p>
   * This reference CDS index provides the constituent legal entities and the payment schedule.
   */
  @PropertyDefinition(validate = "notNull")
  private final CdsIndex underlyingIndex;
  /**
   * The attachment point of the tranche.
   * <p>
   * This is the cumulative loss percentage at which protection begins.
   * Must be between 0.0 and 1.0, and less than the detachment point.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double attachmentPoint;
  /**
   * The detachment point of the tranche.
   * <p>
   * This is the cumulative loss percentage at which protection ends.
   * Must be between 0.0 and 1.0, and greater than the attachment point.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double detachmentPoint;

  //-------------------------------------------------------------------------
  /**
   * Creates an instance of a CDS tranche.
   *
   * @param underlyingIndex  the underlying CDS index
   * @param attachmentPoint  the attachment point
   * @param detachmentPoint  the detachment point
   * @return the instance
   */
  public static CdsTranche of(
      CdsIndex underlyingIndex,
      double attachmentPoint,
      double detachmentPoint) {

    return new CdsTranche(underlyingIndex, attachmentPoint, detachmentPoint);
  }

  @ImmutableDefaults
  private static void applyDefaults(Builder builder) {
  }

  @ImmutablePreBuild
  private static void preBuild(Builder builder) {
    ArgChecker.inRangeExclusive(builder.attachmentPoint, 0d, 1d, "attachmentPoint");
    ArgChecker.inRangeExclusive(builder.detachmentPoint, 0d, 1d, "detachmentPoint");
    ArgChecker.inOrder(builder.attachmentPoint, builder.detachmentPoint,
        "attachmentPoint must be less than detachmentPoint");
  }

  //-------------------------------------------------------------------------
  @Override
  public ImmutableSet<Currency> allCurrencies() {
    return ImmutableSet.of(underlyingIndex.getCurrency());
  }

  //-------------------------------------------------------------------------
  @Override
  public ResolvedCdsTranche resolve(ReferenceData refData) {
    ResolvedCdsIndex resolvedIndex = underlyingIndex.resolve(refData);
    ImmutableList.Builder<CreditCouponPaymentPeriod> accrualPeriods = ImmutableList.builder();
    ImmutableList<CreditCouponPaymentPeriod> indexPeriods = resolvedIndex.getPaymentPeriods();

    // For tranches, we scale the notional by the attachment/detachment spread
    double trancheNotional = underlyingIndex.getNotional() * (detachmentPoint - attachmentPoint);

    for (CreditCouponPaymentPeriod period : indexPeriods) {
      accrualPeriods.add(period.toBuilder()
          .notional(trancheNotional)
          .build());
    }
    ImmutableList<CreditCouponPaymentPeriod> paymentPeriods = accrualPeriods.build();

    return ResolvedCdsTranche.builder()
        .buySell(underlyingIndex.getBuySell())
        .underlyingIndex(resolvedIndex)
        .attachmentPoint(attachmentPoint)
        .detachmentPoint(detachmentPoint)
        .protectionStart(resolvedIndex.getProtectionStart())
        .paymentOnDefault(resolvedIndex.getPaymentOnDefault())
        .paymentPeriods(paymentPeriods)
        .protectionEndDate(resolvedIndex.getProtectionEndDate())
        .settlementDateOffset(resolvedIndex.getSettlementDateOffset())
        .stepinDateOffset(resolvedIndex.getStepinDateOffset())
        .dayCount(resolvedIndex.getDayCount())
        .currency(underlyingIndex.getCurrency())
        .notional(trancheNotional)
        .fixedRate(underlyingIndex.getFixedRate())
        .build();
  }

  /**
   * Gets the attachment point.
   *
   * @return the attachment point
   */
  public double getAttachmentPoint() {
    return attachmentPoint;
  }

  /**
   * Gets the detachment point.
   *
   * @return the detachment point
   */
  public double getDetachmentPoint() {
    return detachmentPoint;
  }

  /**
   * Gets the underlying index.
   *
   * @return the underlying index
   */
  public CdsIndex getUnderlyingIndex() {
    return underlyingIndex;
  }

  /**
   * Gets the currency.
   *
   * @return the currency
   */
  public Currency getCurrency() {
    return underlyingIndex.getCurrency();
  }

  /**
   * Gets the notional.
   *
   * @return the notional
   */
  public double getNotional() {
    return underlyingIndex.getNotional();
  }

  /**
   * Gets the fixed rate.
   *
   * @return the fixed rate
   */
  public double getFixedRate() {
    return underlyingIndex.getFixedRate();
  }

  /**
   * Gets the payment schedule.
   *
   * @return the payment schedule
   */
  public PeriodicSchedule getPaymentSchedule() {
    return underlyingIndex.getPaymentSchedule();
  }

  /**
   * Gets the buy/sell flag.
   *
   * @return the buy/sell flag
   */
  public BuySell getBuySell() {
    return underlyingIndex.getBuySell();
  }

  //------------------------- AUTOGENERATED START -------------------------
  /**
   * The meta-bean for {@code CdsTranche}.
   * @return the meta-bean, not null
   */
  public static CdsTranche.Meta meta() {
    return CdsTranche.Meta.INSTANCE;
  }

  static {
    MetaBean.register(CdsTranche.Meta.INSTANCE);
  }

  /**
   * The serialization version id.
   */
  private static final long serialVersionUID = 1L;

  /**
   * Returns a builder used to create an instance of the bean.
   * @return the builder, not null
   */
  public static CdsTranche.Builder builder() {
    return new CdsTranche.Builder();
  }

  private CdsTranche(
      CdsIndex underlyingIndex,
      double attachmentPoint,
      double detachmentPoint) {
    JodaBeanUtils.notNull(underlyingIndex, "underlyingIndex");
    this.underlyingIndex = underlyingIndex;
    this.attachmentPoint = attachmentPoint;
    this.detachmentPoint = detachmentPoint;
  }

  @Override
  public CdsTranche.Meta metaBean() {
    return CdsTranche.Meta.INSTANCE;
  }

  @Override
  public <R> R property(String propertyName, Class<R> cls) {
    return metaBean().metaProperty(propertyName).get(this, cls);
  }

  @Override
  public Object property(String propertyName) {
    return metaBean().metaProperty(propertyName).get(this);
  }

  @Override
  public void propertyDefaults(Builder builder) {
  }

  @Override
  public boolean equals(Object obj) {
    if (obj == this) {
      return true;
    }
    if (obj != null && obj.getClass() == this.getClass()) {
      CdsTranche other = (CdsTranche) obj;
