  private static void preBuild(Builder builder) {
    if (builder.underlyingIndex != null) {
      if (!(builder.attachmentPoint >= 0d && builder.attachmentPoint < 1d)) {
        throw new IllegalArgumentException("attachmentPoint must be in range [0, 1)");
      }
      if (!(builder.detachmentPoint > 0d && builder.detachmentPoint <= 1d)) {
